#include <stdio.h>
#include <stdint.h>
#include <string.h>

/*
 * Interrupt-Driven I/O Example
 * 
 * This example demonstrates:
 * 1. Memory-mapped device registers
 * 2. Interrupt Service Routine (ISR) setup
 * 3. Interrupt-driven data transfer (vs polling)
 */

/* Device Register Addresses (Memory-Mapped I/O) */
#define UART0_BASE 0x4000C000
#define UART0_DR (*(volatile uint32_t *)(UART0_BASE + 0x00)) // Data Register
#define UART0_RSR (*(volatile uint32_t *)(UART0_BASE + 0x04)) // Receive Status
#define UART0_FR (*(volatile uint32_t *)(UART0_BASE + 0x18)) // Flag Register
#define UART0_IBRD (*(volatile uint32_t *)(UART0_BASE + 0x24)) // Integer Baud Rate
#define UART0_FBRD (*(volatile uint32_t *)(UART0_BASE + 0x28)) // Fractional Baud Rate
#define UART0_LCRH (*(volatile uint32_t *)(UART0_BASE + 0x2C)) // Line Control
#define UART0_CR (*(volatile uint32_t *)(UART0_BASE + 0x30)) // Control Register
#define UART0_IMSC (*(volatile uint32_t *)(UART0_BASE + 0x38)) // Interrupt Mask
#define UART0_MIS (*(volatile uint32_t *)(UART0_BASE + 0x40)) // Masked Interrupt Status
#define UART0_ICR (*(volatile uint32_t *)(UART0_BASE + 0x44)) // Interrupt Clear

/* Flag Register Bits */
#define UART_FR_TXFF 0x00000020 // Transmit FIFO full
#define UART_FR_RXFE 0x00000010 // Receive FIFO empty
#define UART_FR_TXFE 0x00000080 // Transmit FIFO empty

/* Interrupt Mask Bits */
#define UART_IMSC_TXIM 0x00000020 // Transmit interrupt mask
#define UART_IMSC_RXIM 0x00000010 // Receive interrupt mask

/* Global variables for interrupt-driven I/O */
volatile uint8_t tx_buffer[256]; // Transmit buffer
volatile uint16_t tx_head = 0; // TX buffer head (writer)
volatile uint16_t tx_tail = 0; // TX buffer tail (reader/ISR)
volatile uint8_t rx_buffer[256]; // Receive buffer
volatile uint16_t rx_head = 0; // RX buffer head (writer/ISR)
volatile uint16_t rx_tail = 0; // RX buffer tail (reader)
volatile uint8_t interrupts_enabled = 0;

/* Interrupt Service Routine for UART
 * 
 * This function is called by hardware when:
 * - Data arrives (RX interrupt)
 * - Device is ready for more data (TX interrupt)
 * 
 * Key advantage: CPU can do other work instead of polling!
 */
void uart_isr(void) {
 /* Read masked interrupt status to determine cause */
 uint32_t mis = UART0_MIS;

 /* Handle receive interrupt - data available */
 if (mis & UART_IMSC_RXIM) {
 /* While data available, read it into buffer */
 while (!(UART0_FR & UART_FR_RXFE)) {
 uint32_t data = UART0_DR & 0xFF; // Read data register

 /* Add to receive buffer (simple circular buffer) */
 uint16_t next_head = (rx_head + 1) % 256;
 if (next_head != rx_tail) {
 rx_buffer[rx_head] = (uint8_t)data;
 rx_head = next_head;
 }
 }
 /* Clear RX interrupt */
 UART0_ICR = UART_IMSC_RXIM;
 }

 /* Handle transmit interrupt - device ready for data */
 if (mis & UART_IMSC_TXIM) {
 /* While TX FIFO not full and we have data to send */
 while (!(UART0_FR & UART_FR_TXFF)) {
 if (tx_head != tx_tail) {
 /* Get next byte from TX buffer */
 UART0_DR = tx_buffer[tx_tail];
 tx_tail = (tx_tail + 1) % 256;
 } else {
 /* No more data - disable TX interrupt to prevent continuous firing */
 UART0_IMSC &= ~UART_IMSC_TXIM;
 break;
 }
 }
 /* Clear TX interrupt */
 UART0_ICR = UART_IMSC_TXIM;
 }
}

/* Initialize UART for interrupt-driven operation */
void uart_init(void) {
 /* Disable UART during configuration */
 UART0_CR = 0;

 /* Set baud rate (115200 = 16MHz / 16 / 8.68 ≈ 115207) */
 UART0_IBRD = 8;
 UART0_FBRD = 44;

 /* Configure line control: 8N1 (8 data, no parity, 1 stop) */
 UART0_LCRH = (0x3 << 5) | (0x1 << 4); // FEN=1, WLEN=11 (8 bits)

 /* Clear interrupt masks */
 UART0_IMSC = 0;

 /* Enable interrupts: RX and TX */
 UART0_IMSC = UART_IMSC_RXIM | UART_IMSC_TXIM;

 /* Enable UART, TX, and RX */
 UART0_CR = (1 << 0) | (1 << 8) | (1 << 9); // UARTEN=1, TXE=1, RXE=1

 interrupts_enabled = 1;
 printf("UART initialized for interrupt-driven I/O\n");
}

/* Non-blocking transmit - adds data to buffer, interrupt handles actual TX */
int uart_write(const char *data, size_t len) {
 for (size_t i = 0; i < len; i++) {
 /* Check if buffer has space */
 uint16_t next_head = (tx_head + 1) % 256;

 /* Wait if buffer full (in real system, could return error) */
 while (next_head == tx_tail) {
 /* Buffer full - in practice, return error or block */
 }

 tx_buffer[tx_head] = data[i];
 tx_head = next_head;
 }

 /* Enable TX interrupt to start transmission */
 if (interrupts_enabled) {
 UART0_IMSC |= UART_IMSC_TXIM;
 }

 return len;
}

/* Non-blocking receive - reads from buffer filled by ISR */
int uart_read(char *data, size_t max_len) {
 size_t bytes_read = 0;

 while (rx_head != rx_tail && bytes_read < max_len) {
 data[bytes_read] = rx_buffer[rx_tail];
 rx_tail = (rx_tail + 1) % 256;
 bytes_read++;
 }

 return bytes_read;
}

/* Simulate hardware interrupt occurring */
void simulate_uart_interrupt(void) {
 printf("\n[SIMULATION] Hardware interrupt triggered!\n");

 /* Simulate incoming data */
 const char test_data[] = "Data from UART";
 for (int i = 0; test_data[i]; i++) {
 rx_buffer[rx_head] = test_data[i];
 rx_head = (rx_head + 1) % 256;
 }

 /* Call the ISR */
 uart_isr();
}

int main(void) {
 printf("=" * 60);
 printf("\nInterrupt-Driven I/O Demonstration\n");
 printf("=" * 60);

 /* Initialize UART */
 uart_init();

 /* Demonstrate non-blocking write */
 printf("\n--- Non-blocking UART Write ---\n");
 uart_write("Hello, UART!", 12);
 printf("Data queued for transmission\n");
 printf("(ISR will actually transmit when UART is ready)\n");

 /* Simulate hardware interrupt */
 simulate_uart_interrupt();

 /* Read received data */
 printf("\n--- Reading Received Data ---\n");
 char rx_data[64];
 int n = uart_read(rx_data, sizeof(rx_data));
 if (n > 0) {
 rx_data[n] = '\0';
 printf("Received %d bytes: \"%s\"\n", n, rx_data);
 }

 printf("\n" + "=" * 60);
 printf("Key Difference from Polling:");
 printf("\n- Polling: CPU constantly checks device status");
 printf("\n- Interrupt: CPU does useful work, device notifies when ready");
 printf("\n" + "=" * 60);

 return 0;
}

#include <stdio.h>
#include <stdint.h>
#include <string.h>

/*
 * Direct Memory Access (DMA) Controller Example
 * 
 * DMA allows devices to transfer data directly to/from memory
 * without continuous CPU intervention. This example shows:
 * 1. DMA controller configuration
 * 2. Memory-to-memory DMA transfer
 * 3. Interrupt handling for DMA completion
 */

/* DMA Controller Register Map (typical ARM DMA) */
typedef struct {
 volatile uint32_t SAR; // Source Address Register
 volatile uint32_t DAR; // Destination Address Register 
 volatile uint32_t CCR; // Channel Control Register
 volatile uint32_t CNDTR; // Number of Data Items to Transfer
} DMA_Channel_t;

/* DMA Controller Base Address */
#define DMA1_BASE 0x40026000
#define DMA1_CH3 ((DMA_Channel_t *)(DMA1_BASE + 0x0C))

/* Control Register Bit Definitions */
#define DMA_CCR_EN (1 << 0) // Channel Enable
#define DMA_CCR_TCIE (1 << 1) // Transfer Complete Interrupt Enable
#define DMA_CCR_HTIE (1 << 2) // Half Transfer Interrupt Enable
#define DMA_CCR_TEIE (1 << 3) // Transfer Error Interrupt Enable
#define DMA_CCR_DIR (1 << 4) // Direction: 0=Periph->Mem, 1=Mem->Mem
#define DMA_CCR_CIRC (1 << 5) // Circular Mode
#define DMA_CCR_PINC (1 << 6) // Peripheral Increment Mode
#define DMA_CCR_MINC (1 << 7) // Memory Increment Mode
#define DMA_CCR_PSIZE_0 (1 << 8) // Peripheral Size: 0=8-bit, 1=16-bit
#define DMA_CCR_PSIZE_1 (1 << 9)
#define DMA_CCR_MSIZE_0 (1 << 10) // Memory Size: 0=8-bit, 1=16-bit
#define DMA_CCR_MSIZE_1 (1 << 11)
#define DMA_CCR_PL_0 (1 << 12) // Priority: 0=Low, 1=Medium
#define DMA_CCR_PL_1 (1 << 13) // 3=Very High

/* DMA Status Flags */
volatile uint8_t dma_transfer_complete = 0;
volatile uint8_t dma_transfer_error = 0;

/* Source and Destination Buffers */
#define BUFFER_SIZE 1024
uint8_t source_buffer[BUFFER_SIZE];
uint8_t dest_buffer[BUFFER_SIZE];

/* DMA Channel 3 Interrupt Handler */
void DMA1_Channel3_IRQHandler(void) {
 /* Read status - determine what happened */
 /* In real hardware, check specific status registers */

 /* Check for transfer complete */
 /* This would be checking (DMA1->ISR & DMA_ISR_TCIF3) */

 /* For simulation, assume successful completion */
 dma_transfer_complete = 1;

 printf("[DMA ISR] Transfer complete!\n");

 /* Clear interrupt flags */
 /* In real hardware: DMA1->IFCR = DMA_IFCR_CTCIF3; */
}

/* Setup DMA for memory-to-memory transfer */
void dma_setup_transfer(DMA_Channel_t *channel, 
 void *src, void *dst, uint32_t count) {

 /* Disable channel before configuration */
 channel->CCR = 0;

 /* Wait for any previous transfer to complete */
 while (channel->CCR & DMA_CCR_EN);

 /* Set source address */
 channel->SAR = (uint32_t)src;

 /* Set destination address */
 channel->DAR = (uint32_t)dst;

 /* Set number of data items to transfer */
 channel->CNDTR = count;

 /* Configure Channel Control Register:
 * - Memory increment mode (MINC): Increment memory address
 * - Peripheral increment mode (PINC): Not used for mem-to-mem
 * - Memory size (MSIZE): 8-bit
 * - Peripheral size (PSIZE): 8-bit 
 * - Direction (DIR): Memory to memory (set bit)
 * - Transfer complete interrupt enable (TCIE)
 */
 channel->CCR = DMA_CCR_MINC | DMA_CCR_DIR | DMA_CCR_TCIE;

 /* Note: For memory-to-memory, we can't use peripheral */
 /* So we use a trick: treat source as "peripheral" */
 channel->CCR |= DMA_CCR_PINC; // Increment source too

 printf("[DMA] Configuration complete\n");
 printf(" Source: 0x%08X\n", (uint32_t)src);
 printf(" Destination: 0x%08X\n", (uint32_t)dst);
 printf(" Count: %u bytes\n", count);
}

/* Start DMA transfer */
void dma_start(DMA_Channel_t *channel) {
 /* Clear flags */
 dma_transfer_complete = 0;
 dma_transfer_error = 0;

 /* Enable DMA channel - transfer starts immediately */
 channel->CCR |= DMA_CCR_EN;

 printf("[DMA] Transfer started (CPU is now free!)\n");
}

/* Wait for DMA transfer to complete (blocking) */
void dma_wait_complete(void) {
 printf("[DMA] Waiting for completion...\n");
 while (!dma_transfer_complete && !dma_transfer_error);

 if (dma_transfer_error) {
 printf("[DMA] Transfer error occurred!\n");
 }
}

/* Verify transfer was successful */
int dma_verify_transfer(uint8_t *src, uint8_t *dst, uint32_t len) {
 for (uint32_t i = 0; i < len; i++) {
 if (src[i] != dst[i]) {
 printf("[DMA] Verification failed at byte %u: expected 0x%02X, got 0x%02X\n",
 i, src[i], dst[i]);
 return 0;
 }
 }
 return 1;
}

/* Compare three DMA transfer modes */
void demonstrate_dma_modes(void) {
 printf("\n" "========================================\n");
 printf(" DMA Transfer Modes Comparison\n");
 printf("========================================\n\n");

 printf("1. BURST MODE (Block Transfer)\n");
 printf(" - DMA transfers entire block at once\n");
 printf(" - CPU is blocked during transfer\n");
 printf(" - Fastest but CPU idle\n\n");

 printf("2. CYCLE STEALING MODE\n");
 printf(" - DMA transfers one word at a time\n");
 printf(" - 'Steals' bus cycles from CPU\n");
 printf(" - CPU can execute between transfers\n\n");

 printf("3. TRANSPARENT MODE\n");
 printf(" - DMA transfers only when CPU idle\n");
 printf(" - No cycle stealing\n");
 printf(" - Slowest but no CPU impact\n\n");
}

int main(void) {
 printf("========================================\n");
 printf(" DMA Controller Demonstration\n");
 printf("========================================\n");

 /* Initialize source buffer with test data */
 printf("\n[Setup] Initializing source buffer...\n");
 for (int i = 0; i < BUFFER_SIZE; i++) {
 source_buffer[i] = (uint8_t)(i & 0xFF);
 }

 /* Clear destination buffer */
 memset(dest_buffer, 0xAA, BUFFER_SIZE); // Fill with pattern to verify

 /* Show initial state */
 printf("Source[0]: 0x%02X\n", source_buffer[0]);
 printf("Dest[0]: 0x%02X (before DMA)\n", dest_buffer[0]);

 /* Configure DMA for memory-to-memory transfer */
 printf("\n[Setup] Configuring DMA channel 3...\n");
 dma_setup_transfer(DMA1_CH3, source_buffer, dest_buffer, BUFFER_SIZE);

 /* Demonstrate DMA modes */
 demonstrate_dma_modes();

 /* Start DMA transfer */
 printf("\n[Execute] Starting DMA transfer...\n");
 dma_start(DMA1_CH3);

 /* Simulate CPU doing other work while DMA runs */
 printf("\n[CPU] Doing other work while DMA transfers...\n");
 printf(" - Processing user input\n");
 printf(" - Running other tasks\n");
 printf(" - Updating display\n");

 /* Simulate DMA completion (in real system, this is interrupt-driven) */
 printf("\n[Simulated] DMA interrupt fires...\n");
 DMA1_Channel3_IRQHandler();

 /* Wait for completion */
 dma_wait_complete();

 /* Verify transfer */
 printf("\n[Verify] Checking transfer integrity...\n");
 if (dma_verify_transfer(source_buffer, dest_buffer, BUFFER_SIZE)) {
 printf(" SUCCESS: All %d bytes transferred correctly!\n", BUFFER_SIZE);
 }

 /* Show results */
 printf("\n Source[0]: 0x%02X\n", source_buffer[0]);
 printf(" Dest[0]: 0x%02X (after DMA)\n", dest_buffer[0]);

 printf("\n========================================\n");
 printf(" DMA vs Programmed I/O\n");
 printf("========================================\n");
 printf("Programmed I/O: CPU copies every byte\n");
 printf("DMA: CPU sets up transfer, then free\n");
 printf("For 1KB: ~1024 CPU instructions vs 1 setup\n");
 printf("========================================\n");

 return 0;
}
